import{c as e,Q as a,j as n,m as r}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Tenants","description":"","frontmatter":{},"headers":[],"relativePath":"guide/portal/tenants.md","filePath":"guide/portal/tenants.md","lastUpdated":1778912818000}'),s={name:"guide/portal/tenants.md"};function i(o,t,l,d,g,h){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="tenants" tabindex="-1">Tenants <a class="header-anchor" href="#tenants" aria-label="Permalink to &quot;Tenants&quot;">​</a></h1><p>The <strong>Tenants</strong> page in the Customer Portal lists every tenant your customer owns. From here you create new tenants, manage their lifecycle, and drill into each tenant for users and analytics.</p><p>A tenant is a logical environment where your end-users sign in to use Exto&#39;s product. Most customers have one tenant per environment (DEV, QA, PROD).</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><ul><li><strong>New Tenant</strong> button (top right).</li><li><strong>Search</strong> by name or environment.</li><li><strong>Status</strong> filter.</li><li><strong>Clear</strong> when any filter is active.</li></ul><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Tenant Name</strong></td><td>Clickable link to the tenant detail page.</td></tr><tr><td><strong>Env</strong></td><td>Environment badge — PROD / DEV / QA / etc.</td></tr><tr><td><strong>Status</strong></td><td>Active / Suspended / Archived / Provisioning.</td></tr><tr><td><strong>Created</strong></td><td>Date created.</td></tr><tr><td><strong>Actions</strong></td><td>Row-hover icon buttons.</td></tr></tbody></table><h3 id="row-actions" tabindex="-1">Row actions <a class="header-anchor" href="#row-actions" aria-label="Permalink to &quot;Row actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Available when</th></tr></thead><tbody><tr><td><strong>Suspend</strong> (pause)</td><td>Active</td></tr><tr><td><strong>Resume</strong> (play)</td><td>Suspended</td></tr><tr><td><strong>Restore</strong> (rotate)</td><td>Archived</td></tr></tbody></table><h2 id="creating-a-new-tenant" tabindex="-1">Creating a new tenant <a class="header-anchor" href="#creating-a-new-tenant" aria-label="Permalink to &quot;Creating a new tenant&quot;">​</a></h2><p>Click <strong>New Tenant</strong>. A modal asks for the <strong>name</strong>. Other configuration (environment, modules, licensing, address, contact) is set up on the tenant&#39;s detail page after creation.</p><h2 id="tenant-detail-page" tabindex="-1">Tenant detail page <a class="header-anchor" href="#tenant-detail-page" aria-label="Permalink to &quot;Tenant detail page&quot;">​</a></h2><p>The detail page has three tabs.</p><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Editable cards arranged in a two-column grid:</p><ul><li><strong>Details</strong> — Name, Environment, Description, Idle Timeout, Created / Updated dates.</li><li><strong>Primary Contact</strong> — Name, Phone, Email.</li><li><strong>Address</strong> — Street, City, Pincode, Country.</li><li><strong>Licensing &amp; Features</strong> — User and Project license counts, License Expiration, GeoTagging / Angular Dashboard / PowerBI Dashboard toggles.</li></ul><p>Each card has <strong>Edit</strong> / <strong>Cancel</strong> / <strong>Save</strong> buttons. Only changed fields are persisted.</p><h3 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h3><p>A paginated table of users assigned to this tenant.</p><ul><li><strong>Columns</strong> — Name, Email, Role, Status, Provisioned instances.</li><li><strong>Filters</strong> — Status, Role.</li><li><strong>Toolbar</strong> — Bulk Assign, Invite Users (visible if you have <code>manage_tenant_users</code>).</li><li><strong>Row actions</strong> — Activate / Deactivate, Resend invite (for invited users).</li></ul><h4 id="inviting-users" tabindex="-1">Inviting users <a class="header-anchor" href="#inviting-users" aria-label="Permalink to &quot;Inviting users&quot;">​</a></h4><p>Click <strong>Invite Users</strong>. The bulk modal lets you paste emails or upload an Excel file. The review step shows:</p><ul><li>Users already in the customer — flagged and skipped.</li><li>Users existing in the system but not in this customer — flagged with a warning and granted access.</li><li>Genuinely new users — added with the role you choose.</li></ul><h4 id="bulk-assigning-existing-users" tabindex="-1">Bulk-assigning existing users <a class="header-anchor" href="#bulk-assigning-existing-users" aria-label="Permalink to &quot;Bulk-assigning existing users&quot;">​</a></h4><p>Click <strong>Bulk Assign</strong>. Pick the tenant (or it is preselected to the current one), search for users you already have, pick a role for each, and assign.</p><h3 id="insights" tabindex="-1">Insights <a class="header-anchor" href="#insights" aria-label="Permalink to &quot;Insights&quot;">​</a></h3><p>Usage analytics for the tenant.</p><ul><li><strong>Date range</strong> toggle — 7d / 30d / 90d.</li><li><strong>Summary cards</strong> — MAU, Avg DAU, Total Workflows, Avg Error Rate.</li><li><strong>Daily Active Users</strong> chart.</li><li>Side-by-side tables — Workflow Executions, Error Rate by date.</li></ul><p>Error rate ≥ 1% shows in red; &lt; 1% in green. Numeric values use a monospaced font for alignment.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Requires</th></tr></thead><tbody><tr><td>View any of this</td><td><code>view_tenants</code></td></tr><tr><td>Suspend / Resume / Restore</td><td><code>manage_tenant_users</code></td></tr><tr><td>Invite Users, Bulk Assign</td><td><code>manage_tenant_users</code></td></tr><tr><td>Activate / Deactivate users, change role</td><td><code>manage_tenant_users</code></td></tr><tr><td>Edit tenant cards</td><td><code>manage_tenant_users</code></td></tr></tbody></table>',32)])])}const m=e(s,[["render",i]]);export{u as __pageData,m as default};
